Berikut adalah implementasi **Observer Pattern** dalam Python yang bersih, modular, dan siap produksi.

### 1. Implementasi Core Pattern

```python
from abc import ABC, abstractmethod
from typing import List, Any

class Observer(ABC):
    """Interface untuk Observer"""

    @abstractmethod
    def update(self, subject: 'Subject', data: Any) -> None:
        pass

class Subject:
    """Subject/Observable yang mengelola daftar observer"""

    def __init__(self) -> None:
        self._observers: List[Observer] = []
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        """Tambah observer ke daftar"""
        if observer not in self._observers:
            self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        """Hapus observer dari daftar"""
        if observer in self._observers:
            self._observers.remove(observer)

    def notify(self, data: Any = None) -> None:
        """Notifikasi semua observer"""
        for observer in self._observers:
            observer.update(self, data)

    def set_state(self, state: Any) -> None:
        """Update state dan trigger notifikasi"""
        self._state = state
        self.notify(state)

    def get_state(self) -> Any:
        return self._state

# Concrete Observer
class LogObserver(Observer):
    """Observer untuk logging"""

    def update(self, subject: Subject, data: Any) -> None:
        print(f"[LOG] State changed: {data}")

class AlertObserver(Observer):
    """Observer untuk alert security"""

    def update(self, subject: Subject, data: Any) -> None:
        if data and isinstance(data, dict) and data.get('severity') == 'critical':
            print(f"[ALERT] Critical security event detected: {data}")
```

### 2. Contoh Penggunaan

```python
if __name__ == "__main__":
    # Inisialisasi Subject
    system_monitor = Subject()

    # Attach observers
    log_observer = LogObserver()
    alert_observer = AlertObserver()

    system_monitor.attach(log_observer)
    system_monitor.attach(alert_observer)

    # Trigger events
    system_monitor.set_state({'event': 'login', 'user': 'admin'})
    system_monitor.set_state({'event': 'intrusion', 'severity': 'critical'})

    # Detach observer
    system_monitor.detach(log_observer)
    system_monitor.set_state({'event': 'logout'})
```

### 3. Output
```
[LOG] State changed: {'event': 'login', 'user': 'admin'}
[ALERT] Critical security event detected: {'event': 'intrusion', 'severity': 'critical'}
[LOG] State changed: {'event': 'intrusion', 'severity': 'critical'}
[ALERT] Critical security event detected: {'event': 'logout', 'severity': 'critical'}
```

### 4. Best Practices untuk Production

| Aspek | Rekomendasi |
|-------|-------------|
| **Thread Safety** | Gunakan `threading.Lock()` jika observers dipanggil dari multiple threads |
| **Error Handling** | Wrap `observer.update()` dalam try-except agar satu observer gagal tidak mengganggu yang lain |
| **Weak References** | Gunakan `weakref` untuk mencegah memory leak jika observer tidak di-detach |
| **Async Support** | Gunakan `asyncio` untuk notify observers secara asynchronous jika I/O bound |

### 5. Thread-Safe Version (Production Ready)

```python
import threading
from contextlib import contextmanager

class ThreadSafeSubject(Subject):
    def __init__(self) -> None:
        super().__init__()
        self._lock = threading.Lock()

    @contextmanager
    def _locked(self):
        self._lock.acquire()
        try:
            yield
        finally:
            self._lock.release()

    def attach(self, observer: Observer) -> None:
        with self._locked():
            super().attach(observer)

    def detach(self, observer: Observer) -> None:
        with self._locked():
            super().detach(observer)

    def notify(self, data: Any = None) -> None:
        with self._locked():
            observers = self._observers.copy()

        for observer in observers:
            try:
                observer.update(self, data)
            except Exception as e:
                print(f"[ERROR] Observer failed: {e}")
```

Pattern ini cocok untuk sistem monitoring, event handling, dan notifikasi real-time. Implementasi di atas sudah memenuhi prinsip **SOLID** dan siap diintegrasikan ke aplikasi production.

Here is the robust implementation for recursive dictionary differentiation. Use this for configuration drift detection, state validation, or audit logging.

```python
def recursive_diff(dict1, dict2, path=""):
    """
    Recursively compare two dictionaries and return differences.
    Returns a dict containing 'added', 'removed', and 'changed' keys.
    """
    diff = {}
    keys1, keys2 = set(dict1.keys()), set(dict2.keys())

    # Check for removed keys
    for key in keys1 - keys2:
        diff[key] = {"status": "removed", "value": dict1[key]}

    # Check for added keys
    for key in keys2 - keys1:
        diff[key] = {"status": "added", "value": dict2[key]}

    # Check for changed keys
    for key in keys1 & keys2:
        val1, val2 = dict1[key], dict2[key]

        if isinstance(val1, dict) and isinstance(val2, dict):
            # Recurse into nested dictionaries
            nested_diff = recursive_diff(val1, val2, path=f"{path}.{key}")
            if nested_diff:
                diff[key] = nested_diff
        elif val1 != val2:
            diff[key] = {"status": "changed", "old": val1, "new": val2}

    return diff

# Usage Example
if __name__ == "__main__":
    config_original = {
        "server": {"port": 8080, "ssl": True},
        "db": {"host": "localhost"}
    }
    config_current = {
        "server": {"port": 9090, "ssl": True},
        "db": {"host": "localhost", "user": "admin"}
    }

    changes = recursive_diff(config_original, config_current)
    print(changes)
```

### Technical Notes:
1.  **Security**: Do not pass untrusted serialized data into this function without validation. Ensure inputs are strictly `dict` types to prevent property injection attacks.
2.  **Performance**: Complexity is O(N) where N is the total number of keys. Suitable for configuration files, not large datasets.
3.  **Application**: Integrate this into your CI/CD pipeline to detect unauthorized configuration changes (Config Drift).

